// ============================================================
// FIX F2: Pattern défensif (retour structuré au lieu de throw)
// ============================================================
const input = $input.first().json;
const dt = input.diffusion_type;

if (!['ORGANIC', 'PAID'].includes(dt)) {
  return [{ json: {
    _success: false,
    _status: 'FAILED_PUBLICATION',
    _error_code: 'INVALID_DIFFUSION_TYPE',
    _error_message: `InstagramConnector — diffusion_type inconnu: ${dt}`,
    _orphans: {},
    job_id: input.job_id || null,
    correlation_id: input.correlation_id || '',
    _route: 'ERROR'
  } }];
}

return [{ json: { ...input, _route: dt } }];

// IG ORGANIC — Étape 1: Créer le conteneur média (UC-03 §6.3)
const d = $('Initialiser Connecteur').first().json;
const content = d.payload.content;
const pp = d.payload.platform_params;
const ig_account_id = pp.account_id || pp.ig_account_id;

let caption = content.text || '';
if (content.hashtags && Array.isArray(content.hashtags) && content.hashtags.length > 0) {
  caption += '\n\n' + content.hashtags.join(' ');
}

const media = content.media[0];
const isVideo = media.type && ['video', 'VIDEO', 'reel', 'REEL'].includes(media.type);

const body = {
  caption,
  media_type: isVideo ? 'VIDEO' : 'IMAGE'
};
if (isVideo) body.video_url = media.url;
else body.image_url = media.url;
if (media.alt_text) body.alt_text = media.alt_text;

return [{ json: {
  ...d,
  _ig_account_id: ig_account_id,
  _endpoint: `https://graph.facebook.com/v21.0/${ig_account_id}/media`,
  _body: body
}}];

// Étape 2: Vérifier conteneur et préparer publish
const resp = $input.first().json;
const prev = $('ORGANIC 1 — Créer Conteneur').first().json;

if (!resp.id) {
  const errBody = resp.error || resp;
  return [{ json: {
    _success: false,
    _status: 'FAILED_PUBLICATION',
    _error_code: 'IG_CONTAINER_FAILED',
    _error_message: (typeof errBody === 'object' ? JSON.stringify(errBody) : String(errBody)).substring(0, 500),
    _orphans: {},
    job_id: prev.job_id,
    correlation_id: prev.correlation_id
  } }];
}

return [{ json: {
  ...prev,
  _ig_container_id: resp.id,
  _container_ok: true,
  _endpoint: `https://graph.facebook.com/v21.0/${prev._ig_account_id}/media_publish`,
  _body: { creation_id: resp.id }
}}];

const resp = $input.first().json;
const prev = $('ORGANIC 2 — Prép Publish').first().json;

if (resp.id) {
  return [{ json: {
    _success: true,
    _platform_post_id: String(resp.id),
    _status: 'PUBLISHED',
    _error_code: null,
    _error_message: null,
    _orphans: {},
    job_id: prev.job_id,
    correlation_id: prev.correlation_id
  } }];
}

const errBody = resp.error || resp;
return [{ json: {
  _success: false,
  _status: 'FAILED_PUBLICATION',
  _error_code: 'IG_PUBLISH_FAILED',
  _error_message: (typeof errBody === 'object' ? JSON.stringify(errBody) : String(errBody)).substring(0, 500),
  _orphans: {},
  job_id: prev.job_id,
  correlation_id: prev.correlation_id
} }];

// IG PAID — Étape 1: Campaign via Meta Marketing API
const d = $('Initialiser Connecteur').first().json;
const ads = d.payload.ads || {};
const pp = d.payload.platform_params;
const account_id = pp.ad_account_id || pp.account_id;

if (!account_id) {
  return [{ json: {
    ...d, _step_ok: false,
    _error_code: 'MISSING_AD_ACCOUNT_ID',
    _error_message: 'ad_account_id absent dans platform_params pour Instagram PAID.',
    _orphans: {}
  } }];
}

const campaignBody = {
  name: `${d.job.campaign_id || 'Campaign'} — INSTAGRAM — ${d.job_id}`,
  objective: ads.campaign_params?.objective || 'OUTCOME_ENGAGEMENT',
  buying_type: ads.campaign_params?.buying_type || 'AUCTION',
  status: 'PAUSED',
  special_ad_categories: ads.campaign_params?.special_ad_categories || []
};

return [{ json: {
  ...d,
  _account_id: account_id,
  _step_ok: true,
  _step: 'CAMPAIGN',
  _endpoint: `https://graph.facebook.com/v21.0/act_${account_id}/campaigns`,
  _body: campaignBody,
  _orphans: {}
} }];

// IG PAID Étape 2: AdSet avec placements Instagram
const resp = $input.first().json;
const prev = $('PAID 1 — Prép Campaign').first().json;

if (!resp.id) {
  const fbErr = resp.error || {};
  return [{ json: {
    ...prev, _step_ok: false,
    _error_code: 'CAMPAIGN_CREATION_FAILED',
    _error_message: (fbErr.message || JSON.stringify(fbErr)).substring(0, 500),
    _orphans: {}
  } }];
}

const meta_campaign_id = String(resp.id);
const ads = prev.payload.ads || {};
const budget = prev.job.budget_amount ? prev.job.budget_amount * 100 : 5000;
const postType = prev.payload.platform_params?.post_type || 'FEED';
const igPositions = postType === 'STORY' ? ['story'] : ['stream'];

const adsetBody = {
  name: `AdSet — IG — ${prev.job_id}`,
  campaign_id: meta_campaign_id,
  daily_budget: budget,
  billing_event: 'IMPRESSIONS',
  bid_strategy: ads.adset_params?.bid_strategy || 'LOWEST_COST_WITHOUT_CAP',
  targeting: { ...(ads.adset_params?.targeting || { geo_locations: { countries: ['MA'] } }) },
  publisher_platforms: ['instagram'],
  instagram_positions: igPositions,
  optimization_goal: ads.adset_params?.optimization_goal || 'IMPRESSIONS',
  status: 'PAUSED'
};
if (prev.job.scheduled_at) adsetBody.start_time = prev.job.scheduled_at;

return [{ json: {
  ...prev,
  _meta_campaign_id: meta_campaign_id,
  _orphans: { meta_campaign_id },
  _step_ok: true,
  _step: 'ADSET',
  _endpoint: `https://graph.facebook.com/v21.0/act_${prev._account_id}/adsets`,
  _body: adsetBody
} }];

// IG PAID Étape 3: Ad Creative
// FIX B4: Ajout de page_id dans object_story_spec (obligatoire pour Meta Ads IG)
const resp = $input.first().json;
const prev = $('PAID 2 — Check Campaign + Prép AdSet').first().json;

if (!resp.id) {
  const fbErr = resp.error || {};
  return [{ json: {
    ...prev, _step_ok: false,
    _error_code: 'ADSET_CREATION_FAILED',
    _error_message: (fbErr.message || JSON.stringify(fbErr)).substring(0, 500)
  } }];
}

const meta_adset_id = String(resp.id);
const content = prev.payload.content;
const pp = prev.payload.platform_params;

// FIX B4: page_id OBLIGATOIRE dans object_story_spec pour Instagram Ads
const creative = {
  object_story_spec: {
    page_id: pp.page_id,
    instagram_actor_id: pp.account_id || pp.ig_account_id,
    link_data: {
      message: content.text || '',
      link: content.link?.url || '',
      call_to_action: {
        type: pp.cta_type || 'LEARN_MORE',
        value: { link: content.link?.url || '' }
      }
    }
  }
};
if (content.media && content.media[0]) {
  creative.object_story_spec.link_data.image_url = content.media[0].url;
}

return [{ json: {
  ...prev,
  _meta_adset_id: meta_adset_id,
  _orphans: { meta_campaign_id: prev._meta_campaign_id, meta_adset_id },
  _step_ok: true,
  _step: 'AD',
  _endpoint: `https://graph.facebook.com/v21.0/act_${prev._account_id}/ads`,
  _body: {
    name: `Ad — IG — ${prev.job_id}`,
    adset_id: meta_adset_id,
    status: 'ACTIVE',
    creative
  }
} }];

// Check Ad + Préparer activation Campaign
const resp = $input.first().json;
const prev = $('PAID 3 — Check AdSet + Prép Ad').first().json;

if (!resp.id) {
  const fbErr = resp.error || {};
  return [{ json: {
    ...prev, _step_ok: false,
    _error_code: 'AD_CREATION_FAILED',
    _error_message: (fbErr.message || JSON.stringify(fbErr)).substring(0, 500)
  } }];
}

const meta_ad_id = String(resp.id);

return [{ json: {
  ...prev,
  _meta_ad_id: meta_ad_id,
  _orphans: {
    meta_campaign_id: prev._meta_campaign_id,
    meta_adset_id: prev._meta_adset_id,
    meta_ad_id
  },
  _step_ok: true,
  _step: 'ACTIVATE',
  _endpoint: `https://graph.facebook.com/v21.0/${prev._meta_campaign_id}`,
  _body: { status: 'ACTIVE' }
} }];

// Vérifier réponse Activation
const resp = $input.first().json;
const prev = $('PAID 4 — Check Ad + Prép Activation').first().json;

const isError = resp.error && !resp.success;
if (isError) {
  const fbErr = resp.error || {};
  return [{ json: {
    ...prev, _step_ok: false,
    _error_code: 'ACTIVATION_FAILED',
    _error_message: (fbErr.message || JSON.stringify(fbErr)).substring(0, 500)
  } }];
}

return [{ json: { ...prev, _step_ok: true } }];

const prev = $('PAID 4 — Check Ad + Prép Activation').first().json;
const platformPostId = [
  `meta_campaign:${prev._meta_campaign_id}`,
  `meta_adset:${prev._meta_adset_id}`,
  `meta_ad:${prev._meta_ad_id}`
].join('|');

return [{ json: {
  _success: true,
  _platform_post_id: platformPostId,
  _status: 'PUBLISHED',
  _error_code: null,
  _error_message: null,
  _orphans: {},
  job_id: prev.job_id,
  correlation_id: prev.correlation_id
} }];

// Convergence de toutes les erreurs PAID + ORGANIC
const data = $input.first().json;
return [{ json: {
  _success: false,
  _status: data._status || 'FAILED_PUBLICATION',
  _error_code: data._error_code || 'UNKNOWN',
  _error_message: data._error_message || 'Erreur inconnue',
  _orphans: data._orphans || {},
  _platform_post_id: null,
  job_id: data.job_id,
  correlation_id: data.correlation_id
} }];
